import {
  NumberField,
  StringField,
  StringFieldOptional,
} from "../../../decorators/field.decorators.ts";

export class PaymentResponseDto {
  @StringField()
  transactionId!: string;

  @StringField()
  status!: string;

  @NumberField()
  amount!: number;

  @StringField()
  currency!: string;

  @StringField()
  accountNumber!: string;

  @StringField()
  accountName!: string;

  @StringFieldOptional()
  inquiryId?: string;

  @StringFieldOptional()
  txnStatusId?: string;

  @StringField()
  message!: string;
}
